<template>
    <div ref="divRef" :class="['tinyflow', className]" :style="style" />
</template>

<script setup lang="ts">
import { Tinyflow as TinyflowNative, TinyflowOptions } from '@tinyflow-ai/ui';
import '@tinyflow-ai/ui/dist/index.css';
import { onMounted, onUnmounted, ref, watch } from 'vue';

const props = defineProps<
    {
        className?: string;
        style?: Record<string, string>;
    } & Omit<TinyflowOptions, 'element'>
>();

const divRef = ref<HTMLDivElement | null>(null);
let tinyflow: TinyflowNative | null = null;

// 安全深拷贝工具函数
function safeDeepClone<T>(obj: T): T {
    if (obj === null || typeof obj !== 'object') return obj;

    try {
        return structuredClone(obj);
    } catch {
        try {
            return JSON.parse(JSON.stringify(obj));
        } catch {
            console.warn('Failed to clone object, returning original (may cause issues)', obj);
            return obj;
        }
    }
}

// 初始化 Tinyflow 实例
function initTinyflow() {
    if (divRef.value) {
        // 销毁旧实例
        if (tinyflow) {
            tinyflow.destroy();
            tinyflow = null;
        }
        
        // 净化 props.data，避免响应式对象或函数污染
        const cleanedProps = { ...props } as any;
        if ('data' in cleanedProps && cleanedProps.data != null) {
            cleanedProps.data = safeDeepClone(cleanedProps.data);
        }

        tinyflow = new TinyflowNative({
            ...cleanedProps,
            element: divRef.value
        });
    }
}

onMounted(() => {
    initTinyflow();
});

// 监听 customNodes 属性变化，重新初始化实例
watch(() => props.customNodes, () => {
    initTinyflow();
}, { deep: true });

// 监听 data 属性变化，重新初始化实例
watch(() => props.data, () => {
    initTinyflow();
}, { deep: true });

onUnmounted(() => {
    if (tinyflow) {
        tinyflow.destroy();
        tinyflow = null;
    }
});

const getData = () => {
    if (tinyflow) {
        return tinyflow.getData();
    }
    console.warn('Tinyflow instance is not initialized');
    return null;
};

const validate = () => {
    if (tinyflow) {
        return tinyflow.validate();
    }
    console.warn('Tinyflow instance is not initialized');
    return {
        success: false,
        errors: [{ message: 'Tinyflow instance is not initialized' }]
    };
};

const setData = (data: any) => {
    if (tinyflow) {
        return tinyflow.setData(data);
    }
    console.warn('Tinyflow instance is not initialized');
    return null;
};

const updateNodeData = (id: string, data: any) => {
    if (tinyflow) {
        return tinyflow.updateNodeData(id, data);
    }
    console.warn('Tinyflow instance is not initialized');
    return null;
};

defineExpose({
    getData,
    validate,
    setData,
    updateNodeData
});
</script>
